import{_ as t,o as a,c as o,a2 as r}from"./chunks/framework.IwO0Hdn_.js";const m=JSON.parse('{"title":"[UI / PRESENTATION] F-03.3 — Editor de Texto Enriquecido para Comentarios","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-03.3_editor_rich_text.md","filePath":"backlog/F-03.3_editor_rich_text.md","lastUpdated":null}'),n={name:"backlog/F-03.3_editor_rich_text.md"};function i(s,e,d,c,l,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="ui-presentation-f-03-3-—-editor-de-texto-enriquecido-para-comentarios" tabindex="-1">[UI / PRESENTATION] F-03.3 — Editor de Texto Enriquecido para Comentarios <a class="header-anchor" href="#ui-presentation-f-03-3-—-editor-de-texto-enriquecido-para-comentarios" aria-label="Permalink to &quot;[UI / PRESENTATION] F-03.3 — Editor de Texto Enriquecido para Comentarios&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-03 — Detalle y Archivado de un Log</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>UI / Presentation</code><strong>Secundaria:</strong> <code>DX / Tooling</code><strong>Impacta en:</strong> Equipo Frontend (Livewire/Blade)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.1_setup_laravel_livewire.html">F-00.1</a></td><td>Entorno npm disponible (<code>npm install @tiptap/core @tiptap/starter-kit @tiptap/extension-image @tiptap/extension-link</code>) y Composer para <code>mews/purifier</code></td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero escribir comentarios usando un editor rich text que me permita dar formato al texto e insertar imágenes Para documentar la resolución de un error con capturas de pantalla y contexto visual detallado</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Formato texto):</strong> Dado que estoy escribiendo un comentario, cuando aplico negrita, cursiva, listas o encabezados, entonces el formato se preserva al guardar y al visualizar posteriormente.</li><li>[ ] <strong>Escenario 2 (Imágenes):</strong> Dado que arrastro o pego una imagen en el editor, cuando se inserta, entonces la imagen queda embebida en el comentario y es visible en la vista de detalle del histórico.</li><li>[ ] <strong>Escenario 3 (Límite de tamaño):</strong> Dado que intento subir una imagen mayor de 2 MB, cuando se intenta insertar, entonces el editor muestra un mensaje de error y no la incluye.</li><li>[ ] <strong>Escenario 4 (Seguridad XSS):</strong> Dado que el admin guarda un comentario con HTML potencialmente malicioso, cuando el backend lo persiste, entonces el contenido pasa por sanitización server-side (DOMPurify/HTMLPurifier) antes de almacenarse.</li><li>[ ] <strong>Requisito Técnico:</strong> Usar <strong>TipTap 2</strong> integrado con Livewire vía Alpine.js bridge: un componente Alpine captura el HTML del editor y lo sincroniza con <code>$wire.set(&#39;commentContent&#39;, html)</code>. Extensiones: StarterKit, Image, Link. Almacenar contenido como HTML sanitizado (HTMLPurifier en backend). Límite total de comentario: 10 MB (STRIDE D-RTE-01). Validar MIME type real de imágenes en backend (STRIDE E-RTE-01).</li></ul>',12)])])}const g=t(n,[["render",i]]);export{m as __pageData,g as default};
